class Person:
    # Class variable (shared by all instances)
    species = 'Homo sapiens'
    count = 0

    def __init__(self, name, age):
        # Instance variables (unique to each object)
        self.name = name
        self.age = age
        Person.count += 1

    def greet(self):
        return f'Hi, I am {self.name}, {self.age} years old'

    @classmethod
    def get_count(cls):
        return f'Total persons: {cls.count}'

    @staticmethod
    def is_adult(age):
        return age >= 18

    def __str__(self):
        return f'Person({self.name}, {self.age})'

    def __repr__(self):
        return f'Person(name={self.name!r}, age={self.age!r})'

    def __eq__(self, other):
        return self.name == other.name and self.age == other.age

    def __lt__(self, other):
        return self.age < other.age

p1 = Person('Alice', 25)
p2 = Person('Bob', 30)
print(p1.greet())
print(Person.get_count())
print(Person.is_adult(20))
print(p1 == Person('Alice', 25))
print(sorted([p2, p1], key=lambda p: p.age))

# Single inheritance
class Animal:
    def __init__(self, name):
        self.name = name
    def speak(self): return f'{self.name} makes a sound'
    def __str__(self): return f'{self.__class__.__name__}({self.name})'

class Dog(Animal):
    def speak(self): return f'{self.name}: Woof!'
    def fetch(self): return f'{self.name} fetches!'

# Multiple inheritance
class Flyable:
    def fly(self): return 'I can fly!'

class Swimmable:
    def swim(self): return 'I can swim!'

class Duck(Animal, Flyable, Swimmable):
    def speak(self): return f'{self.name}: Quack!'

duck = Duck('Donald')
print(duck.speak())
print(duck.fly())
print(duck.swim())
print(Duck.__mro__)  # Method Resolution Order

# Multilevel inheritance
class Vehicle:
    def __init__(self, brand):
        self.brand = brand
    def start(self): return f'{self.brand} started'

class Car(Vehicle):
    def __init__(self, brand, model):
        super().__init__(brand)
        self.model = model

class ElectricCar(Car):
    def __init__(self, brand, model, battery):
        super().__init__(brand, model)
        self.battery = battery
    def charge(self): return f'Charging {self.battery}kWh battery'

tesla = ElectricCar('Tesla', 'Model 3', 75)
print(tesla.start())
print(tesla.charge())

from abc import ABC, abstractmethod
import math

class Shape(ABC):
    @abstractmethod
    def area(self): pass

    @abstractmethod
    def perimeter(self): pass

    def describe(self):
        return f'{self.__class__.__name__}: area={self.area():.2f}, perimeter={self.perimeter():.2f}'

class Circle(Shape):
    def __init__(self, r): self.r = r
    def area(self): return math.pi * self.r**2
    def perimeter(self): return 2 * math.pi * self.r

class Rectangle(Shape):
    def __init__(self, w, h): self.w, self.h = w, h
    def area(self): return self.w * self.h
    def perimeter(self): return 2*(self.w+self.h)

class Triangle(Shape):
    def __init__(self, a, b, c): self.a,self.b,self.c = a,b,c
    def area(self):
        s = (self.a+self.b+self.c)/2
        return math.sqrt(s*(s-self.a)*(s-self.b)*(s-self.c))
    def perimeter(self): return self.a+self.b+self.c

shapes = [Circle(5), Rectangle(4,6), Triangle(3,4,5)]
for s in shapes:
    print(s.describe())

class Temperature:
    def __init__(self, celsius=0):
        self._celsius = celsius

    @property
    def celsius(self):
        return self._celsius

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError('Temperature below absolute zero!')
        self._celsius = value

    @property
    def fahrenheit(self):
        return self._celsius * 9/5 + 32

    @fahrenheit.setter
    def fahrenheit(self, value):
        self.celsius = (value - 32) * 5/9

    @property
    def kelvin(self):
        return self._celsius + 273.15

    def __repr__(self):
        return f'Temperature({self._celsius}°C / {self.fahrenheit}°F / {self.kelvin}K)'

t = Temperature(100)
print(t)
t.fahrenheit = 32
print(t)
t.celsius = -273.15
print(t)

class Vector:
    def __init__(self, x, y, z=0):
        self.x, self.y, self.z = x, y, z

    # String representations
    def __str__(self): return f'Vector({self.x}, {self.y}, {self.z})'
    def __repr__(self): return f'Vector(x={self.x}, y={self.y}, z={self.z})'

    # Arithmetic
    def __add__(self, o): return Vector(self.x+o.x, self.y+o.y, self.z+o.z)
    def __sub__(self, o): return Vector(self.x-o.x, self.y-o.y, self.z-o.z)
    def __mul__(self, scalar): return Vector(self.x*scalar, self.y*scalar, self.z*scalar)
    def __rmul__(self, scalar): return self.__mul__(scalar)
    def __neg__(self): return Vector(-self.x, -self.y, -self.z)

    # Comparison
    def __eq__(self, o): return self.x==o.x and self.y==o.y and self.z==o.z
    def __abs__(self): return (self.x**2+self.y**2+self.z**2)**0.5
    def __len__(self): return 3

    # Container
    def __getitem__(self, i): return (self.x,self.y,self.z)[i]
    def __iter__(self): return iter((self.x,self.y,self.z))
    def __contains__(self, val): return val in (self.x,self.y,self.z)

    # Boolean
    def __bool__(self): return bool(self.x or self.y or self.z)

v1 = Vector(1, 2, 3)
v2 = Vector(4, 5, 6)
print(v1 + v2)
print(v1 * 3)
print(abs(v1))
print(list(v1))
print(2 in v1)
print(bool(Vector(0,0,0)))
